import re

def get_unique_genes(text: str):
    """
    Extract unique gene symbols from a block of text in the format:
    'Up-regulated (N): GENE1, GENE2, ...'
    'Down-regulated (M): GENE3, GENE4, ...'
    """
    # Regex to capture the gene list part after 'Up-regulated (...) :' or 'Down-regulated (...) :'
    pattern = r'(?:Up-regulated|Down-regulated)\s*\([^)]*\):\s*(.*?)\n'
    
    # Use DOTALL so '.' can span long lines if needed, but here we stop at newline
    matches = re.findall(pattern, text, flags=re.DOTALL)
    
    genes = []
    for block in matches:
        # Split on commas and clean spaces
        parts = [g.strip() for g in block.split(',')]
        genes.extend([g for g in parts if g])  # drop empty
    
    return sorted(set(genes))


def count_unique_genes(text: str) -> int:
    """Return the number of unique genes in the text."""
    return len(get_unique_genes(text))

def parse_celltype_genes(text: str):
    """
    Parse the long 'Genes Selected for Pathway Analysis' text into:
        { "CellType": {gene1, gene2, ...}, ... }
    """
    celltype_genes = {}

    # Split by cell type blocks
    blocks = re.split(r'^Cell Type:\s*', text, flags=re.MULTILINE)
    # First element is header; ignore
    for block in blocks[1:]:
        # First line is the header: e.g. "Macrophages (293 genes selected)"
        header, *rest = block.split('\n', 1)
        cell_type = header.split('(')[0].strip()
        body = rest[0] if rest else ""

        # Within this block, get all Up-/Down-regulated gene lists
        pattern = r'(?:Up-regulated|Down-regulated)\s*\([^)]*\):\s*(.*)'
        matches = re.findall(pattern, body)

        genes = set()
        for m in matches:
            parts = [g.strip() for g in m.split(',')]
            genes.update(g for g in parts if g)

        celltype_genes[cell_type] = genes

    return celltype_genes


def compute_overlaps(text1: str, markers_dict: dict):
    """
    Compute overlaps between genes in text1 and markers_dict,
    *restricted to the same cell type*.

    Returns:
        overlaps: {cell_type: {"count": int, "genes": [..]}}
        total_overlap: int  (sum over all cell types)
    """
    ct_genes = parse_celltype_genes(text1)

    overlaps = {}
    total = 0

    for cell_type, info in markers_dict.items():
        markers = set(info.get('markers', []))
        if cell_type in ct_genes:
            shared = markers & ct_genes[cell_type]
        else:
            shared = set()

        overlaps[cell_type] = {
            "count": len(shared),
            "genes": sorted(shared)
        }
        total += len(shared)

    return overlaps, total


